import { ref } from 'vue'
import { useStore } from 'vuex'
import { auth } from '@/api/auth'
import { SMS_SCENE } from '@/constants'
import { showToast } from '@/components/ToastMessage'

export function usePhone() {
  const store = useStore()
  const value = ref('')
  const code = ref('')
  const loading = ref(false)
  const showModal = ref(false)
  const countdown = ref(0)

  const handleSendCode = async () => {
    if (!/^1[3-9]\d{9}$/.test(value.value)) {
      showToast('请输入正确的手机号', 'warning')
      return
    }

    try {
      loading.value = true
      await auth.sendVerifyCode({
        phone: value.value,
        scene: SMS_SCENE.CHANGE_PHONE
      })
      showToast('验证码已发送', 'success')
      countdown.value = 60
      const timer = setInterval(() => {
        countdown.value--
        if (countdown.value <= 0) {
          clearInterval(timer)
        }
      }, 1000)
    } catch (error) {
      showToast(error.response?.data?.message || '发送失败', 'error')
    } finally {
      loading.value = false
    }
  }

  const handleUpdate = async () => {
    if (!value.value || !code.value) {
      showToast('请填写完整信息', 'warning')
      return
    }

    try {
      loading.value = true
      await auth.changePhone({
        phone: value.value,
        code: code.value
      })
      await store.dispatch('fetchUserInfo')
      showToast('手机号更新成功', 'success')
      showModal.value = false
    } catch (error) {
      showToast(error.response?.data?.message || '更新失败', 'error')
    } finally {
      loading.value = false
    }
  }

  const closeModal = () => {
    showModal.value = false
    value.value = ''
    code.value = ''
    countdown.value = 0
  }

  return {
    value,
    code,
    loading,
    showModal,
    countdown,
    handleSendCode,
    handleUpdate,
    closeModal
  }
}
